output [31:0] count;
wire [31:0] count;
input clk;
input rst;

reg [31:0] cnt = 0;
reg clkOut_i = 0;



always @(posedge clk, posedge rst) begin: CLOCKDIVIDER_COUNTER
    if (rst) begin
        cnt <= 0;
    end
    else if (($signed({1'b0, cnt}) == ($signed({1'b0, Divisor}) - 1))) begin
        cnt <= 0;
    end
    else begin
        cnt <= (cnt + 1);
    end
end


always @(posedge clk, posedge rst) begin: CLOCKDIVIDER_CLOCKTICK
    if (rst) begin
        clkOut_i <= 0;
    end
    else if (($signed({1'b0, cnt}) == ($signed({1'b0, Divisor}) - 1))) begin
        clkOut_i <= (!clkOut_i);
    end
    else begin
        clkOut_i <= clkOut_i;
    end
end



assign count = cnt;
assign clkOut = clkOut_i;

